#include "mutex_lock.h"
static SemaphoreHandle_t _mtx=NULL;
void mutex_setup(){_mtx=xSemaphoreCreateMutex();Serial.println("[mutex] OK");}
bool mutex_take(uint32_t ms){return xSemaphoreTake(_mtx,ms/portTICK_PERIOD_MS)==pdTRUE;}
void mutex_give(){xSemaphoreGive(_mtx);}
